def plan_format_reward(completions, **kwargs):
    import re
    pattern = re.compile(r'^<think>.*</think>\s*<answer>.*</answer>$', re.DOTALL)
    rewards = []
    for comp in completions:
        content = comp.get('content', '')
        if pattern.fullmatch(content):
            rewards.append(1.0)
        else:
            rewards.append(0.0)
    return rewards

